24	__global__ void getPaddingOffsetAndCuSeqLensKernel(size_t*    h_valid_word_num,
25	                                                   int*       tmp_mask_offset,
26	                                                   int*       cu_seqlens,
27	                                                   const int* sequence_length,
28	                                                   const int  batch_size,
29	                                                   const int  max_seq_len)
30	{
31	    // do cumulated sum
32	    int        total_seq_len        = 0;
33	    int        cum_offset           = 0;
34	    int        index                = 0;
35	    const bool calculate_cu_seqlens = cu_seqlens != nullptr;
36	    for (int i = 0; i < batch_size; i++) {
37	        const int seq_len = sequence_length[i];
38	        if (calculate_cu_seqlens) {
39	            cu_seqlens[i] = total_seq_len;
40	        }
41	        for (int j = 0; j < seq_len; j++) {
42	            tmp_mask_offset[index] = cum_offset;
43	            index++;
44	        }
45	        cum_offset += max_seq_len - seq_len;
46	        total_seq_len += seq_len;
47	    }
48	    if (calculate_cu_seqlens) {
49	        cu_seqlens[batch_size] = total_seq_len;
50	    }
51	    h_valid_word_num[0] = (size_t)total_seq_len;
52	}
