54	void invokeGetPaddingOffsetAndCuSeqLens(size_t*      h_pinned_token_num,
55	                                        size_t*      h_token_num,
56	                                        int*         tmp_mask_offset,
57	                                        int*         cu_seqlens,
58	                                        const int*   sequence_lengths,
59	                                        const int    batch_size,
60	                                        const int    max_seq_len,
61	                                        cudaStream_t stream)
62	{
63	    h_pinned_token_num[0] = 0;
64	    getPaddingOffsetAndCuSeqLensKernel<<<1, 1, 0, stream>>>(
65	        h_pinned_token_num, tmp_mask_offset, cu_seqlens, sequence_lengths, batch_size, max_seq_len);
66	    while (((volatile size_t*)h_pinned_token_num)[0] == 0) {};
67	    h_token_num[0] = h_pinned_token_num[0];
68	    sync_check_cuda_error();
69	}
