72	__global__ void buildEncoderAttentionMaskKernel(T* attention_mask, const int* sequence_lengths, const int max_seq_len)
73	{
74	    // sequence_lengths: [batch_size]
75	    // attention_mask: [batch_size, 1, max_seq_len, max_seq_len]
76	    attention_mask += blockIdx.x * max_seq_len * max_seq_len;
77	    const int length = sequence_lengths[blockIdx.x];
78	    for (int i = threadIdx.x; i < max_seq_len * max_seq_len; i += blockDim.x) {
79	        // int row_id = i / max_seq_len;
80	        int col_id = i % max_seq_len;
81	        // if (row_id < length && col_id < length) {
82	        // TODO (bhsueh) check this modification is ok or not on other rmodel
83	        if (col_id < length) {
84	            attention_mask[i] = (T)(1.0f);
85	        }
86	        else {
87	            attention_mask[i] = (T)(0.0f);
88	        }
89	    }
90	}
