124	__global__ void getTrtPaddingOffsetKernel(int* trt_mha_padding_offset, const int* sequence_length, const int batch_size)
125	{
126	    // use for get tensorrt fused mha padding offset
127	    // when we remove the padding
128	
129	    extern __shared__ int tmp_offset[];
130	    if (threadIdx.x == 0) {
131	        tmp_offset[0] = 0;
132	        for (int i = 0; i < batch_size; i++) {
133	            tmp_offset[i + 1] = tmp_offset[i] + sequence_length[i];
134	        }
135	    }
136	    __syncthreads();
137	
138	    for (int i = threadIdx.x; i < batch_size + 1; i += blockDim.x) {
139	        trt_mha_padding_offset[i] = tmp_offset[i];
140	    }
141	}
