152	__global__ void getTrtPaddingOffsetKernel(int*       trt_mha_padding_offset,
153	                                          const int* sequence_length,
154	                                          const int  request_batch_size,
155	                                          const int  request_seq_len)
156	{
157	    // use for get tensorrt fused mha padding offset
158	    // when we keep the padding
159	
160	    extern __shared__ int tmp_offset[];
161	    if (threadIdx.x == 0) {
162	        tmp_offset[0] = 0;
163	        for (int i = 0; i < request_batch_size; i++) {
164	            tmp_offset[i * 2 + 1] = tmp_offset[i * 2] + sequence_length[i];
165	            tmp_offset[i * 2 + 2] = request_seq_len * (i + 1);
