290	template<typename T>
291	__global__ void buildRelativeAttentionBias(T*         relative_attention_bias,
292	                                           const T*   relative_attention_bias_table,
293	                                           const int  head_num,
294	                                           const int  seq_len,
295	                                           const int  num_bucket,
296	                                           const bool is_bidirectional,
297	                                           const int  max_distance)
298	{
299	
300	    const int head_id = blockIdx.x;
301	    for (int seq_id = threadIdx.x; seq_id < seq_len * seq_len; seq_id += blockDim.x) {
302	        int row_id = seq_id / seq_len;
303	        int col_id = seq_id % seq_len;
304	
305	        int relative_position = col_id - row_id;
306	
307	        int relative_buckets = 0;
308	        int tmp_num_bucket   = num_bucket;
309	        if (is_bidirectional) {
310	            tmp_num_bucket /= 2;
311	            if (relative_position > 0) {
312	                relative_buckets += tmp_num_bucket;
313	            }
314	            else {
315	                relative_position *= -1;
316	            }
317	        }
318	        else {
319	            relative_position = abs(relative_position);
320	        }
321	
322	        int  max_exact = tmp_num_bucket / 2;
323	        bool is_small  = relative_position < max_exact;
324	
325	        int relative_position_if_large =
326	            max_exact
327	            + (int)(logf(relative_position * 1.0f / max_exact) / logf((float)max_distance / max_exact)
328	                    * (tmp_num_bucket - max_exact));
329	
330	        relative_position_if_large = min(relative_position_if_large, tmp_num_bucket - 1);
331	
332	        relative_buckets += is_small ? relative_position : relative_position_if_large;
333	
334	        relative_attention_bias[head_id * seq_len * seq_len + seq_id] =
335	            relative_attention_bias_table[head_id * num_bucket + relative_buckets];
336	    }
337	}
