416	template<typename T_OUT, typename T_IN, QUANTIZE_MODE quantize_mode>
417	__global__ void quantizeMatrixRebuildPadding(QuantizeMatrixRebuildPaddingParam<T_OUT, T_IN, quantize_mode> param)
418	{
419	    for (int i = threadIdx.x; i < param.d_model; i += blockDim.x) {
420	        int padded_row_id = blockIdx.x + (param.padding_offset == nullptr ? 0 : param.padding_offset[blockIdx.x]);
421	        if (quantize_mode == QUANTIZE_MODE::PER_TENSOR) {
422	            param.dst[padded_row_id * param.d_model + i] =
423	                (T_OUT)((float)param.src[blockIdx.x * param.d_model + i] * __ldg(param.scale));
424	        }
425	        else if (quantize_mode == QUANTIZE_MODE::PER_CHANNEL) {
426	            param.dst[padded_row_id * param.d_model + i] =
427	                (T_OUT)((float)param.src[blockIdx.x * param.d_model + i] * __ldg(param.scale + i));
428	        }
429	    }
430	}
431	
432	template<>
433	__global__ void
434	quantizeMatrixRebuildPadding(QuantizeMatrixRebuildPaddingParam<half, __nv_fp8_e4m3, QUANTIZE_MODE::PER_TENSOR> param)
435	{
436	    int padded_row_id = blockIdx.x + (param.padding_offset == nullptr ? 0 : __ldg(&param.padding_offset[blockIdx.x]));
437	    __nv_fp8x4_e4m3* src_ptr = ((__nv_fp8x4_e4m3*)param.src) + blockIdx.x * (param.d_model / 4);
438	    half2*           dst_ptr = ((half2*)param.dst) + padded_row_id * (param.d_model / 2);
439	    half2            scale   = cuda_cast<half2>(__ldg(param.scale));
440	    for (int i = threadIdx.x; i < param.d_model / 4; i += blockDim.x) {
441	        half2 val_0;
442	        half2 val_1;
443	        fp8x4_e4m3_to_half2(&val_0, &val_1, src_ptr + i);
444	
445	        val_0 = hmul2(val_0, scale);
446	        val_1 = hmul2(val_1, scale);
447	
448	        dst_ptr[2 * i + 0] = val_0;
449	        dst_ptr[2 * i + 1] = val_1;
450	    }
451	}
452	
453	template<typename T_OUT, typename T_IN, QUANTIZE_MODE quantize_mode>
454	void invokeQuantizeMatrixRebuildPadding(QuantizeMatrixRebuildPaddingParam<T_OUT, T_IN, quantize_mode> param)
455	{
456	    dim3 grid(param.token_num);
457	    dim3 block(param.d_model);
458	    FT_CHECK(block.x <= 1024);
459	    if (block.x % 4 == 0) {
460	        block.x /= 4;
461	    }
462	    quantizeMatrixRebuildPadding<<<grid, block, 0, param.stream>>>(param);
463	}
